import {
  allowedDistricts,
  allowedTrades,
  allowedUrgency,
  canonicalDistrict,
  customerDisplayName,
  encryptPhone,
  errorResponse,
  getAdminSupabase,
  hashPhone,
  HttpError,
  jsonResponse,
  matchingDistricts,
  normalizeContactMethod,
  normalizeMauritiusWhatsapp,
  optionsResponse,
  readJsonBody,
  requireString,
  safePhotoPath,
  tradeAliases,
} from "../_shared/artisanmu.ts";

type CreateJobBody = {
  urgency?: string;
  description?: string;
  trade?: string;
  district?: string;
  whatsapp_number?: string;
  contact_method?: string;
  photo_url?: string;
  expiry_days?: number;
};

// The poster chooses how long the request stays visible (1–30 days). If it is
// not claimed/completed before then, it auto-expires and disappears from feeds.
function resolveExpiryDays(value: unknown, urgency: string) {
  const requested = Number(value);
  if (Number.isFinite(requested)) {
    return Math.min(30, Math.max(1, Math.round(requested)));
  }
  return urgency === "urgent" ? 2 : 7;
}

type ArtisanTarget = {
  id: number;
  auth_user_id: string | null;
  district: string | null;
  ville: string | null;
  metier: string | null;
};

Deno.serve(async (request: Request) => {
  if (request.method === "OPTIONS") return optionsResponse();
  if (request.method !== "POST") {
    return jsonResponse({ error: "method_not_allowed" }, 405);
  }

  try {
    const body = await readJsonBody<CreateJobBody>(request);
    const urgency = requireString(body.urgency, "urgency");
    const description = requireString(body.description, "description");
    const trade = requireString(body.trade, "trade");
    const district = canonicalDistrict(requireString(body.district, "district"));

    if (!allowedUrgency.includes(urgency)) {
      throw new HttpError(400, "invalid_urgency", "Urgency must be urgent or planned.");
    }
    if (description.length < 10) {
      throw new HttpError(400, "description_too_short", "Describe the problem in at least 10 characters.");
    }
    if (!allowedTrades.includes(trade)) {
      throw new HttpError(400, "invalid_trade", "Choose a supported trade.");
    }
    if (!allowedDistricts.includes(district)) {
      throw new HttpError(400, "invalid_district", "Choose a supported district or island.");
    }

    const supabase = getAdminSupabase();
    const contactMethod = normalizeContactMethod(body.contact_method);
    const e164Phone = normalizeMauritiusWhatsapp(body.whatsapp_number);
    const [phoneHash, encryptedPhone] = await Promise.all([
      hashPhone(e164Phone),
      encryptPhone(e164Phone),
    ]);
    const displayName = customerDisplayName();
    const now = Date.now();
    const expiryDays = resolveExpiryDays(body.expiry_days, urgency);
    const expiresAt = new Date(now + expiryDays * 24 * 60 * 60 * 1000).toISOString();
    const photoPath = safePhotoPath(body.photo_url);

    const { data: targetPool, error: targetError } = await supabase
      .from("artisans")
      .select("id,auth_user_id,district,ville,metier")
      .eq("is_verified", true)
      .eq("verification_status", "approved")
      .not("auth_user_id", "is", null);

    if (targetError) {
      throw new HttpError(500, "target_lookup_failed", targetError.message);
    }

    const districts = matchingDistricts(district);
    const trades = tradeAliases(trade);
    const targets = ((targetPool || []) as ArtisanTarget[]).filter((artisan) => {
      const districtMatch = districts.includes(artisan.district || "") || districts.includes(artisan.ville || "");
      const tradeMatch = trade === "Other" || trades.includes(artisan.metier || "");
      return districtMatch && tradeMatch && artisan.auth_user_id;
    });

    const { data: job, error: jobError } = await supabase
      .from("job_requests")
      .insert({
        category: trade,
        description,
        image_url: photoPath,
        budget_tier: "mid",
        district,
        town: district,
        client_name: displayName,
        customer_display_name: displayName,
        client_whatsapp: "protected",
        whatsapp_hash: phoneHash,
        whatsapp_encrypted: encryptedPhone.encrypted,
        whatsapp_iv: encryptedPhone.iv,
        photo_storage_path: photoPath,
        status: "open",
        urgency,
        contact_method: contactMethod,
        expires_at: expiresAt,
      })
      .select("id")
      .single();

    if (jobError || !job) {
      throw new HttpError(500, "job_insert_failed", jobError?.message || "Could not create job request.");
    }

    if (targets.length) {
      const { error: notificationError } = await supabase.from("job_notifications").insert(
        targets.map((artisan) => ({
          job_id: job.id,
          artisan_id: artisan.id,
          auth_user_id: artisan.auth_user_id,
          urgency,
          status: "pending",
          match_reason: {
            district,
            trade,
            matched_on: {
              district: artisan.district,
              town: artisan.ville,
              trade: artisan.metier,
            },
          },
        })),
      );

      if (notificationError) {
        throw new HttpError(500, "notification_insert_failed", notificationError.message);
      }
    }

    await supabase.from("job_events").insert({
      job_id: job.id,
      event: "created",
      metadata: {
        urgency,
        district,
        trade,
        has_photo: Boolean(photoPath),
        contact_method: contactMethod,
        targeted_artisan_count: targets.length,
      },
    });

    return jsonResponse({
      id: job.id,
      artisan_count_nearby: targets.length,
      targeted_artisan_count: targets.length,
      estimated_response_minutes: urgency === "urgent" ? 18 : 90,
    });
  } catch (error) {
    return errorResponse(error);
  }
});

import { createClient, type SupabaseClient } from "npm:@supabase/supabase-js@2.107.0";

type JsonValue = Record<string, unknown> | unknown[];

export const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, content-type, apikey",
  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
};

let adminClient: SupabaseClient | null = null;
let adminClientKey = "";

const encoder = new TextEncoder();
const decoder = new TextDecoder();
const adminPasswordHashFallback = "fe3ffd2d9a9aaced48c32c451afd6c81ca0a68beb6873dbcb3717755a0150bd9";

export class HttpError extends Error {
  constructor(
    public status: number,
    public code: string,
    message: string,
  ) {
    super(message);
  }
}

export function optionsResponse() {
  return new Response(null, { status: 204, headers: corsHeaders });
}

export function jsonResponse(data: JsonValue | Record<string, unknown>, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json; charset=utf-8" },
  });
}

export function errorResponse(error: unknown) {
  if (error instanceof HttpError) {
    return jsonResponse({ error: error.code, message: error.message }, error.status);
  }

  const message = error instanceof Error ? error.message : "Unexpected server error.";
  return jsonResponse({ error: "server_error", message }, 500);
}

export async function readJsonBody<T>(request: Request): Promise<T> {
  try {
    return (await request.json()) as T;
  } catch {
    throw new HttpError(400, "invalid_json", "The request body must be valid JSON.");
  }
}

export async function sha256Hex(value: string) {
  const hashBuffer = await crypto.subtle.digest("SHA-256", encoder.encode(value));
  return Array.from(new Uint8Array(hashBuffer))
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");
}

export async function verifyAdminPassword(value: unknown) {
  if (typeof value !== "string" || !value.trim()) {
    throw new HttpError(401, "missing_admin_password", "Admin password is required.");
  }

  const expectedHash =
    Deno.env.get("ADMIN_PASSWORD_HASH") ||
    Deno.env.get("NEXT_PUBLIC_ADMIN_PASSWORD_HASH") ||
    adminPasswordHashFallback;
  const candidateHash = await sha256Hex(value.trim());

  if (candidateHash !== expectedHash) {
    throw new HttpError(403, "admin_forbidden", "Admin password is invalid.");
  }
}

function parseSecretKeys() {
  const raw = Deno.env.get("SUPABASE_SECRET_KEYS");
  if (!raw) return "";

  try {
    const parsed = JSON.parse(raw) as Record<string, string>;
    return parsed.default || Object.values(parsed)[0] || "";
  } catch {
    return "";
  }
}

export function getAdminSupabase() {
  const url = Deno.env.get("SUPABASE_URL");
  const key =
    Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ||
    Deno.env.get("SUPABASE_SECRET_KEY") ||
    parseSecretKeys();

  if (!url || !key) {
    throw new HttpError(500, "missing_supabase_config", "Supabase service configuration is missing.");
  }

  const cacheKey = `${url}:${key.slice(0, 12)}`;
  if (!adminClient || adminClientKey !== cacheKey) {
    adminClient = createClient(url, key, {
      auth: { autoRefreshToken: false, persistSession: false },
    });
    adminClientKey = cacheKey;
  }

  return adminClient;
}

function contactSecret() {
  const secret =
    Deno.env.get("CONTACT_ENCRYPTION_KEY") ||
    Deno.env.get("CONTACT_HASH_SALT") ||
    Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ||
    parseSecretKeys();

  if (!secret || secret.length < 16) {
    throw new HttpError(500, "missing_contact_secret", "Contact privacy configuration is missing.");
  }

  return secret;
}

function toBase64(bytes: Uint8Array) {
  let binary = "";
  for (const byte of bytes) binary += String.fromCharCode(byte);
  return btoa(binary);
}

function fromBase64(value: string) {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index += 1) bytes[index] = binary.charCodeAt(index);
  return bytes;
}

async function contactKey() {
  const digest = await crypto.subtle.digest("SHA-256", encoder.encode(contactSecret()));
  return crypto.subtle.importKey("raw", digest, "AES-GCM", false, ["encrypt", "decrypt"]);
}

export async function encryptPhone(value: string) {
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const encrypted = await crypto.subtle.encrypt(
    { name: "AES-GCM", iv },
    await contactKey(),
    encoder.encode(value),
  );

  return {
    encrypted: toBase64(new Uint8Array(encrypted)),
    iv: toBase64(iv),
  };
}

export async function decryptPhone(encrypted: string, iv: string) {
  const decrypted = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv: fromBase64(iv) },
    await contactKey(),
    fromBase64(encrypted),
  );

  return decoder.decode(decrypted);
}

export async function hashPhone(value: string) {
  const salt = Deno.env.get("CONTACT_HASH_SALT") || contactSecret();
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(salt),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"],
  );
  const signature = await crypto.subtle.sign("HMAC", key, encoder.encode(value));
  return Array.from(new Uint8Array(signature))
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");
}

export function normalizeMauritiusWhatsapp(value: unknown) {
  if (typeof value !== "string") {
    throw new HttpError(400, "missing_whatsapp", "A WhatsApp number is required.");
  }

  const digits = value.replace(/\D/g, "");
  const local = digits.startsWith("230") ? digits.slice(3) : digits;

  if (!/^[24579]\d{7}$/.test(local)) {
    throw new HttpError(400, "invalid_whatsapp", "Enter a valid Mauritius WhatsApp number.");
  }

  return `+230${local}`;
}

export function whatsappDeepLink(phone: string, message: string) {
  const digits = phone.replace(/\D/g, "");
  return `https://wa.me/${digits}?text=${encodeURIComponent(message)}`;
}

export function telLink(phone: string) {
  return `tel:${phone.replace(/[^\d+]/g, "")}`;
}

export const allowedContactMethods = ["whatsapp", "call"];

export function normalizeContactMethod(value: unknown) {
  return value === "call" ? "call" : "whatsapp";
}

export function requireString(value: unknown, field: string) {
  if (typeof value !== "string" || !value.trim()) {
    throw new HttpError(400, `missing_${field}`, `${field} is required.`);
  }

  return value.trim();
}

export function customerDisplayName() {
  return `Client ${Math.floor(100 + Math.random() * 900)}`;
}

export const allowedUrgency = ["urgent", "planned"];
export const allowedTrades = [
  "Plumber",
  "Electrician",
  "Painter",
  "Carpenter",
  "Mason",
  "AC technician",
  "Locksmith",
  "Gardener",
  "Plombier",
  "Electricien",
  "Électricien",
  "Peintre",
  "Menuisier",
  "Macon",
  "Maçon",
  "Climatisation",
  "Serrurier",
  "Jardinier",
  "Other",
];

export const canonicalDistricts = [
  "Port Louis",
  "Pamplemousses",
  "Riviere du Rempart",
  "Flacq",
  "Grand Port",
  "Savanne",
  "Plaines Wilhems",
  "Moka",
  "Black River",
  "Rodrigues",
];

const districtAliases: Record<string, string[]> = {
  "Port Louis": ["Port Louis", "Port-Louis"],
  Pamplemousses: ["Pamplemousses"],
  "Riviere du Rempart": ["Riviere du Rempart", "Rivière du Rempart", "Grand Baie"],
  Flacq: ["Flacq"],
  "Grand Port": ["Grand Port", "Mahebourg", "Mahébourg"],
  Savanne: ["Savanne", "Souillac"],
  "Plaines Wilhems": [
    "Plaines Wilhems",
    "Plaine Wilhems",
    "Curepipe",
    "Quatre Bornes",
    "Rose Hill",
    "Vacoas",
    "Phoenix",
    "Beau Bassin",
  ],
  Moka: ["Moka"],
  "Black River": ["Black River", "Riviere Noire", "Rivière Noire"],
  Rodrigues: ["Rodrigues", "Port Mathurin"],
};

export const allowedDistricts = Array.from(
  new Set([...canonicalDistricts, ...Object.values(districtAliases).flat()]),
);

export const allowedServiceTags = [
  "Emergency repair",
  "Same-day service",
  "Leak repair",
  "No power",
  "AC service",
  "Installation",
  "Maintenance",
  "Renovation",
  "Inspection",
  "After-hours",
  "Weekend jobs",
  "Small jobs",
  "Commercial work",
  "Home repairs",
];

export function tradeAliases(trade: string) {
  const aliases: Record<string, string[]> = {
    Plumber: ["Plumber", "Plombier"],
    Plombier: ["Plumber", "Plombier"],
    Electrician: ["Electrician", "Electricien", "Électricien"],
    Electricien: ["Electrician", "Electricien", "Électricien"],
    "Électricien": ["Electrician", "Electricien", "Électricien"],
    Painter: ["Painter", "Peintre"],
    Peintre: ["Painter", "Peintre"],
    Carpenter: ["Carpenter", "Menuisier"],
    Menuisier: ["Carpenter", "Menuisier"],
    Mason: ["Mason", "Macon", "Maçon"],
    Macon: ["Mason", "Macon", "Maçon"],
    "Maçon": ["Mason", "Macon", "Maçon"],
    "AC technician": ["AC technician", "Climatisation", "Technicien clim", "Aircon"],
    Climatisation: ["AC technician", "Climatisation", "Technicien clim", "Aircon"],
    Locksmith: ["Locksmith", "Serrurier"],
    Serrurier: ["Locksmith", "Serrurier"],
    Gardener: ["Gardener", "Jardinier"],
    Jardinier: ["Gardener", "Jardinier"],
    Other: [],
  };

  return aliases[trade] || [trade];
}

function keyFor(value: string) {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

export function canonicalDistrict(value: string) {
  const candidateKey = keyFor(value);
  for (const [district, aliases] of Object.entries(districtAliases)) {
    if (aliases.some((alias) => keyFor(alias) === candidateKey)) return district;
  }

  return value;
}

export function matchingDistricts(district: string) {
  const canonical = canonicalDistrict(district);
  return districtAliases[canonical] || [canonical];
}

export function normalizeServiceTags(value: unknown, requireOne = false) {
  const rawItems = Array.isArray(value)
    ? value
    : typeof value === "string"
      ? value.split(/[\n,;]+/)
      : [];
  const allowedByKey = new Map(allowedServiceTags.map((tag) => [keyFor(tag), tag]));
  const tags = Array.from(
    new Set(
      rawItems
        .map((item) => String(item).trim().replace(/\s+/g, " "))
        .map((item) => allowedByKey.get(keyFor(item)) || item)
        .filter((item) => item.length >= 2 && item.length <= 34),
    ),
  ).slice(0, 8);

  if (requireOne && !tags.length) {
    throw new HttpError(400, "missing_service_tags", "Choose at least one service tag.");
  }

  return tags;
}

export function safePhotoPath(value: unknown) {
  if (typeof value !== "string" || !value.trim()) return null;
  const path = value.trim();
  if (!/^job-photos\/[a-f0-9-]{36}\/\d{13}-[\w.-]+$/i.test(path)) {
    throw new HttpError(400, "invalid_photo_path", "Photo upload path is invalid.");
  }
  return path;
}

export function storagePublicUrl(bucket: string, path: string) {
  const url = Deno.env.get("SUPABASE_URL");

  if (!url) {
    throw new HttpError(500, "missing_supabase_config", "Supabase service configuration is missing.");
  }

  return `${url.replace(/\/$/, "")}/storage/v1/object/public/${bucket}/${path
    .split("/")
    .map((part) => encodeURIComponent(part))
    .join("/")}`;
}
